AWS Glue is a serverless ETL service. Terraform manages the Glue catalog, crawlers (schema discovery), and ETL jobs.

```hcl
# Glue catalog database
resource "aws_glue_catalog_database" "data_lake" {
  name = "data_lake_catalog"
}

# Crawler to discover S3 schema
resource "aws_glue_crawler" "raw_zone" {
  database_name = aws_glue_catalog_database.data_lake.name
  name          = "raw-zone-crawler"
  role          = aws_iam_role.glue_role.arn

  s3_target {
    path = "s3://${aws_s3_bucket.data_lake.bucket}/raw/"
  }

  schedule = "cron(0 6 * * ? *)"  # daily at 6 AM UTC

  configuration = jsonencode({
    Version = 1.0
    Grouping = { TableGroupingPolicy = "CombineCompatibleSchemas" }
  })
}

# Glue ETL job
resource "aws_glue_job" "transform" {
  name     = "raw-to-curated-transform"
  role_arn = aws_iam_role.glue_role.arn

  command {
    script_location = "s3://${aws_s3_bucket.glue_scripts.bucket}/transform.py"
    python_version  = "3"
  }

  default_arguments = {
    "--job-language"        = "python"
    "--enable-metrics"      = "true"
    "--enable-glue-datacatalog" = "true"
    "--TempDir"             = "s3://${aws_s3_bucket.glue_temp.bucket}/temp/"
    "--SOURCE_BUCKET"       = aws_s3_bucket.data_lake.bucket
  }

  number_of_workers = 10
  worker_type       = "G.1X"
  glue_version      = "4.0"
}
```

DE tip: Glue scripts live in S3, not in Terraform. Terraform manages the infrastructure; your CI/CD pipeline deploys the script code separately.
